"use client";
import { useState, useEffect } from "react";
import Header from "@/components/Header";
import { getSupabaseBrowserClient } from "@/lib/supabase/client";

export default function AdminPage() {
    const [activeTab, setActiveTab] = useState("dashboard");
    const [showModal, setShowModal] = useState(false);
    const [modalType, setModalType] = useState("");
    const supabase = getSupabaseBrowserClient();

    const [data, setData] = useState({
        stats: { users: 0, books: 0, loans: 0, fines: 0 },
        logs: [], users: [], books: [], copies: [], places: [],
        loans: [], reservations: [], fines: [], notifications: [], audit: [], roles: []
    });

    const navLinks = [
        { label: "Дашборд", href: "/admin" },
        { label: "Пользователи", href: "/admin?tab=users" },
        { label: "Каталог", href: "/admin?tab=catalog" },
        { label: "Экземпляры", href: "/admin?tab=copies" },
        { label: "Выдачи", href: "/admin?tab=loans" },
        { label: "Бронирования", href: "/admin?tab=reservations" },
        { label: "Штрафы", href: "/admin?tab=fines" },
        { label: "Уведомления", href: "/admin?tab=notifications" },
        { label: "Аудит", href: "/admin?tab=audit" },
    ];

    useEffect(() => {
        const fetchAll = async () => {
            const [
                { count: users }, { count: books }, { count: loans }, { count: fines },
                { data: logs }, { data: roles }, { data: audit }
            ] = await Promise.all([
                supabase.from("пользователи").select("id", { count: "exact", head: true }),
                supabase.from("книги").select("id", { count: "exact", head: true }),
                supabase.from("выдачи").select("id", { count: "exact", head: true }).eq("статус_выдачи", "Активна"),
                supabase.from("штраф").select("id", { count: "exact", head: true }).eq("статус", "Не оплачен"),
                supabase.from("журнал_аудит").select(`
          id, пользователь:пользователи(фио), тип_действия, предмет_действия, ip_адрес, дата_создания
        `).order("дата_создания", { ascending: false }).limit(4),
                supabase.from("роли").select("*"),
                supabase.from("журнал_аудит").select(`
          id, пользователь:пользователи(фио), тип_действия, предмет_действие, предмет_взаимодействия_id, ip_адрес, дата_создания
        `).order("дата_создания", { ascending: false })
            ]);

            setData(prev => ({
                ...prev,
                stats: { users: users || 0, books: books || 0, loans: loans || 0, fines: fines || 0 },
                logs: logs || [],
                roles: roles || [],
                audit: audit || []
            }));
        };
        fetchAll();
    }, []);

    const openModal = (type) => { setModalType(type); setShowModal(true); };
    const closeAll = () => { setShowModal(false); setModalType(""); };

    const formatDate = (d) => d ? new Date(d).toLocaleString("ru-RU", { day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" }) : "—";
    const formatShortDate = (d) => d ? new Date(d).toLocaleDateString("ru-RU") : "—";

    return (
        <>
            <Header
                navLinks={navLinks}
                user={{ name: "Алексей Д.", initials: "АД", role: "Администратор", email: "admin@lib.ru" }}
                notifCount={3}
            />

            <div className="admin-container">
                <div className="page-header">
                    <h1>Панель администратора</h1>
                    <p>Системный обзор — {new Date().toLocaleDateString("ru-RU", { day: "numeric", month: "long", year: "numeric" })}</p>
                </div>

                {activeTab === "dashboard" && (
                    <>
                        <div className="stats-grid">
                            <div className="stat-card">
                                <div className="stat-value" style={{ color: "var(--cyan-400)" }}>{data.stats.users.toLocaleString()}</div>
                                <div className="stat-label">Пользователей <span style={{ color: "var(--green-400)" }}>+15%</span></div>
                            </div>
                            <div className="stat-card">
                                <div className="stat-value">{data.stats.books.toLocaleString()}</div>
                                <div className="stat-label">Книг в фонде <span style={{ color: "var(--green-400)" }}>+8%</span></div>
                            </div>
                            <div className="stat-card">
                                <div className="stat-value" style={{ color: "var(--library-400)" }}>{data.stats.loans}</div>
                                <div className="stat-label">Активных выдач</div>
                            </div>
                            <div className="stat-card">
                                <div className="stat-value" style={{ color: "var(--red-400)" }}>₽45,200</div>
                                <div className="stat-label">Неоплаченных штрафов</div>
                            </div>
                        </div>

                        <div style={{ display: "flex", gap: 12, marginBottom: 24, flexWrap: "wrap" }}>
                            <span className="server-badge st-ready">Основной сервер<br /><small>Uptime: 99.97%</small></span>
                            <span className="server-badge st-ready">База данных<br /><small>Загрузка: 42%</small></span>
                            <span className="server-badge st-waiting">Резервный сервер<br /><small>Синхронизация...</small></span>
                        </div>

                        <div className="table-wrap">
                            <h3 style={{ padding: "16px 20px", borderBottom: "1px solid rgba(255,255,255,0.06)" }}>📜 Системный журнал (журнал_аудит)</h3>
                            <table>
                                <thead><tr><th>Действие</th><th>Пользователь</th><th>IP</th><th>Время</th></tr></thead>
                                <tbody>
                                {data.logs.map(l => (
                                    <tr key={l.id}>
                                        <td>{l.тип_действия} «{l.предмет_действия}»</td>
                                        <td>{l.пользователь?.фио || "Система"}</td>
                                        <td>{l.ip_адрес || "—"}</td>
                                        <td>{formatDate(l.дата_создания)}</td>
                                    </tr>
                                ))}
                                </tbody>
                            </table>
                        </div>
                    </>
                )}

                {activeTab === "users" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>👥 Пользователи</h3>
                            <button className="btn btn-primary btn-sm" onClick={() => openModal("addUser")}>Добавить</button>
                        </div>
                        <div style={{ display: "flex", gap: 8, padding: "0 20px", marginBottom: 12 }}>
                            {["Все", "Читатели", "Библиотекари", "Администраторы", "Заблокированные"].map(f => (
                                <button key={f} className="btn btn-ghost btn-sm">{f}</button>
                            ))}
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>ФИО</th><th>Email</th><th>Телефон</th><th>Роль</th><th>Заблокирован</th><th>Дата создания</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="8" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {activeTab === "catalog" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>📚 Каталог книг</h3>
                            <div style={{ display: "flex", gap: 8 }}>
                                <button className="btn btn-secondary btn-sm" onClick={() => openModal("addBook")}>Добавить книгу</button>
                                <button className="btn btn-secondary btn-sm" onClick={() => openModal("addAuthor")}>Добавить автора</button>
                                <button className="btn btn-secondary btn-sm" onClick={() => openModal("addGenre")}>Добавить жанр</button>
                            </div>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Название</th><th>ISBN</th><th>Издательство</th><th>Год</th><th>Язык</th><th>Страниц</th><th>Всего</th><th>Доступно</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="10" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {activeTab === "copies" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>📖 Физические книги</h3>
                            <div style={{ display: "flex", gap: 8 }}>
                                <button className="btn btn-primary btn-sm" onClick={() => openModal("addCopy")}>Добавить</button>
                                <button className="btn btn-secondary btn-sm" onClick={() => openModal("addPlace")}>Добавить место</button>
                            </div>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Инв. номер</th><th>Штрихкод</th><th>Книга</th><th>Место</th><th>Статус</th><th>Состояние</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="8" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {activeTab === "loans" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>📋 Выдачи</h3>
                            <button className="btn btn-primary btn-sm" onClick={() => openModal("issueBook")}>Оформить</button>
                        </div>
                        <div style={{ display: "flex", gap: 8, padding: "0 20px", marginBottom: 12 }}>
                            {["Все", "Активные", "Возвращённые", "Просроченные"].map(f => (
                                <button key={f} className="btn btn-ghost btn-sm">{f}</button>
                            ))}
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Пользователь</th><th>Физ. книга</th><th>Дата выдачи</th><th>Вернуть до</th><th>Дата возврата</th><th>Продлений</th><th>Статус</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="9" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {activeTab === "reservations" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>📌 Бронирования</h3>
                            <button className="btn btn-primary btn-sm" onClick={() => openModal("createRes")}>Создать</button>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Пользователь</th><th>Книга</th><th>Статус</th><th>Очередь</th><th>Дата бронирования</th><th>Дата истечения</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="8" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {activeTab === "fines" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>💰 Штрафы</h3>
                            <button className="btn btn-primary btn-sm" onClick={() => openModal("addFine")}>Начислить</button>
                        </div>
                        <div className="stats-grid" style={{ padding: "16px 20px", borderBottom: "1px solid rgba(255,255,255,0.06)" }}>
                            <div className="stat-card" style={{ padding: 12 }}><div className="stat-value" style={{ color: "var(--red-400)", fontSize: 18 }}>₽45,200</div><div className="stat-label">Неоплаченных</div></div>
                            <div className="stat-card" style={{ padding: 12 }}><div className="stat-value" style={{ color: "var(--green-400)", fontSize: 18 }}>₽239,300</div><div className="stat-label">Оплачено</div></div>
                            <div className="stat-card" style={{ padding: 12 }}><div className="stat-value" style={{ fontSize: 18 }}>67</div><div className="stat-label">Всего штрафов</div></div>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Выдача</th><th>Сумма</th><th>Причина</th><th>Статус</th><th>Дата выдачи</th><th>Дата оплаты</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="8" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {activeTab === "notifications" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>🔔 Уведомления</h3>
                            <button className="btn btn-secondary btn-sm">Отправить тест</button>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Пользователь</th><th>Заголовок</th><th>Сообщение</th><th>Тип</th><th>Прочитано</th><th>Отправлено через</th><th>Действия</th></tr></thead>
                            <tbody><tr><td colSpan="8" className="empty-row">Показано 0 из 0</td></tr></tbody>
                        </table>
                    </div>
                )}

                {activeTab === "audit" && (
                    <div className="table-wrap">
                        <div className="table-header">
                            <h3>🛡️ Журнал аудит</h3>
                            <button className="btn btn-secondary btn-sm">Экспорт</button>
                        </div>
                        <table>
                            <thead><tr><th>ID</th><th>Пользователь</th><th>Тип действия</th><th>Предмет действия</th><th>Предмет ID</th><th>IP адрес</th><th>Дата создания</th></tr></thead>
                            <tbody>
                            {data.audit.map(a => (
                                <tr key={a.id}>
                                    <td>{a.id}</td><td>{a.пользователь?.фио || "Система"}</td><td>{a.тип_действия}</td>
                                    <td>{a.предмет_действие}</td><td>{a.предмет_взаимодействия_id}</td><td>{a.ip_адрес}</td><td>{formatDate(a.дата_создания)}</td>
                                </tr>
                            ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* MODALS */}
            {showModal && (
                <div className="modal-overlay show" onClick={closeAll}>
                    <div className="modal" onClick={e => e.stopPropagation()}>
                        <button className="modal-close" onClick={closeAll}>✕</button>
                        <div className="modal-hero"><h2 className="modal-title">
                            {modalType === "addUser" && "Добавить пользователя"}
                            {modalType === "addBook" && "Добавить книгу"}
                            {modalType === "addAuthor" && "Добавить автора"}
                            {modalType === "addGenre" && "Добавить жанр"}
                            {modalType === "addCopy" && "Добавить экземпляр"}
                            {modalType === "addPlace" && "Добавить место"}
                            {modalType === "issueBook" && "Оформить выдачу"}
                            {modalType === "createRes" && "Создать бронирование"}
                            {modalType === "addFine" && "Начислить штраф"}
                        </h2></div>
                        <div className="modal-body">
                            {modalType === "addUser" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>ФИО *</span><input placeholder="Иванов Иван Иванович" /></label>
                                    <label><span>Email *</span><input type="email" placeholder="user@mail.ru" /></label>
                                    <label><span>Телефон</span><input type="tel" placeholder="+7 (900) 000-00-00" /></label>
                                    <label><span>Роль *</span><select>{data.roles.map(r => <option key={r.id}>{r.название}</option>)}</select></label>
                                    <label><span>Заблокирован</span><select><option>Нет</option><option>Да</option></select></label>
                                    <label><span>Причина блокировки</span><input placeholder="Оставьте пустым, если нет" /></label>
                                </form>
                            )}
                            {modalType === "addBook" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>Название *</span><input placeholder="Название книги" /></label>
                                    <label><span>ISBN *</span><input placeholder="978-5-00000-000-0" /></label>
                                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                                        <label><span>Год издания</span><input type="number" defaultValue="2024" /></label>
                                        <label><span>Издательство</span><input defaultValue="Эксмо" /></label>
                                    </div>
                                    <label><span>Язык</span><select><option>Русский</option><option>Английский</option><option>Французский</option><option>Немецкий</option></select></label>
                                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                                        <label><span>Количество страниц</span><input type="number" /></label>
                                        <label><span>Всего экземпляров *</span><input type="number" defaultValue="1" /></label>
                                    </div>
                                </form>
                            )}
                            {modalType === "addAuthor" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>ФИО *</span><input placeholder="Пушкин Александр Сергеевич" /></label>
                                    <label><span>Страна</span><input placeholder="Россия" /></label>
                                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                                        <label><span>Год рождения</span><input type="number" /></label>
                                        <label><span>Год смерти</span><input type="number" placeholder="Оставьте пустым, если жив" /></label>
                                    </div>
                                </form>
                            )}
                            {modalType === "addGenre" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>Название *</span><input placeholder="Научная фантастика" /></label>
                                    <label><span>Описание</span><textarea rows="3" placeholder="Краткое описание жанра..." /></label>
                                </form>
                            )}
                            {modalType === "addCopy" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>Книга *</span><select><option>Война и мир</option><option>Преступление и наказание</option><option>Мастер и Маргарита</option><option>1984</option></select></label>
                                    <label><span>Инвентарный номер *</span><input placeholder="INV-2026-001" /></label>
                                    <label><span>Штрихкод *</span><input placeholder="1234567890123" /></label>
                                    <label><span>Место хранения</span><select><option>Зал А — Шкаф 3 — Полка 2</option><option>Зал Б — Шкаф 1 — Полка 4</option></select></label>
                                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                                        <label><span>Статус</span><select><option>Доступен</option><option>Выдан</option><option>Забронирован</option><option>Повреждён</option></select></label>
                                        <label><span>Состояние</span><select><option>Отличное</option><option>Хорошее</option><option>Удовлетворительное</option><option>Требует ремонта</option></select></label>
                                    </div>
                                </form>
                            )}
                            {modalType === "addPlace" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>Название *</span><input placeholder="Зал А" /></label>
                                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                                        <label><span>Зал</span><input /></label>
                                        <label><span>Секция</span><input /></label>
                                    </div>
                                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                                        <label><span>Шкаф</span><input /></label>
                                        <label><span>Полка</span><input /></label>
                                    </div>
                                    <label><span>Описание</span><textarea rows="2" /></label>
                                </form>
                            )}
                            {modalType === "issueBook" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>Пользователь *</span><select><option>Анна Ковалёва</option><option>Дмитрий Сидоров</option><option>Мария Иванова</option></select></label>
                                    <label><span>Физическая книга *</span><select><option>INV-2024-001 (Война и мир)</option><option>INV-2024-005 (1984)</option></select></label>
                                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                                        <label><span>Дата выдачи *</span><input type="date" /></label>
                                        <label><span>Вернуть до *</span><input type="date" /></label>
                                    </div>
                                </form>
                            )}
                            {modalType === "createRes" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>Пользователь *</span><select><option>Анна Ковалёва</option><option>Дмитрий Сидоров</option></select></label>
                                    <label><span>Книга *</span><select><option>Война и мир</option><option>1984</option><option>Мастер и Маргарита</option></select></label>
                                    <label><span>Статус бронирования</span><select><option>Ожидает</option><option>Активно</option><option>Завершено</option><option>Отменено</option></select></label>
                                </form>
                            )}
                            {modalType === "addFine" && (
                                <form style={{ display: "grid", gap: 16 }}>
                                    <label><span>Выдача *</span><select><option>#1001 — Война и мир</option><option>#1003 — 1984</option></select></label>
                                    <label><span>Сумма (₽) *</span><input type="number" placeholder="50" /></label>
                                    <label><span>Статус</span><select><option>Не оплачен</option><option>Оплачен</option></select></label>
                                    <label><span>Причина *</span><input placeholder="Просрочка возврата" /></label>
                                    <label><span>Комментарий</span><textarea rows="2" /></label>
                                </form>
                            )}
                        </div>
                        <div className="modal-footer">
                            <button className="btn btn-secondary btn-block" onClick={closeAll}>Отмена</button>
                            <button className="btn btn-primary btn-block">Сохранить</button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}